<?php namespace App\Repositories\Academic;use App\Repositories\BaseRepository;use App\Models\Academic\ClassModel;use Illuminate\Database\Eloquent\Collection;class ClassRepository extends BaseRepository{    public function __construct(ClassModel $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?ClassModel    {        return $this->query()->where('name', $name)->first();    }    public function findByNumeric(int $numeric): ?ClassModel    {        return $this->query()->where('numeric', $numeric)->first();    }    public function getActiveClasses(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getClassWithSections(int $classId): ?ClassModel    {        return $this->query()->with('sections')->findOrFail($classId);    }    public function getClassWithSubjects(int $classId): ?ClassModel    {        return $this->query()->with('subjects')->findOrFail($classId);    }    public function searchClasses(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('numeric', 'like', "%{$keyword}%")->get();    }    public function getByEducationBoard(string $board): Collection    {        return $this->findByField('education_board', $board);    }    public function getPromotionFlow(int $classId): ?ClassModel    {        $class = $this->getById($classId);        if ($class->next_class_id) {            return $this->getById($class->next_class_id);        }        return null;    }}